1	package validation
2	
3	import (
4		"fmt"
5		"strings"
6	
7		"github.com/go-git/go-git/v6/plumbing"
8	)
9	
10	const (
11		ProtocolAuto = "auto"
12		ProtocolV1   = "v1"
13		ProtocolV2   = "v2"
14	)
15	
16	// RefMapping is a user-specified source:target mapping.
17	type RefMapping struct {
18		Source string
19		Target string
20	}
21	
22	// NormalizedMapping is a validated mapping normalized to fully-qualified refs.
23	type NormalizedMapping struct {
24		SourceRef plumbing.ReferenceName
25		TargetRef plumbing.ReferenceName
26	}
27	
28	// NormalizeProtocolMode validates the configured protocol mode and applies the
29	// default auto mode when the user did not specify one.
30	func NormalizeProtocolMode(mode string) (string, error) {
31		if mode == "" {
32			return ProtocolAuto, nil
33		}
34		switch mode {
35		case ProtocolAuto, ProtocolV1, ProtocolV2:
36			return mode, nil
37		default:
38			return "", fmt.Errorf("unsupported protocol mode %q", mode)
39		}
40	}
41	
42	// ParseMapping parses a CLI --map value into a ref mapping.
43	func ParseMapping(raw string) (RefMapping, error) {
44		parts := strings.SplitN(raw, ":", 2)
45		if len(parts) != 2 {
46			return RefMapping{}, fmt.Errorf("invalid --map %q, expected src:dst", raw)
47		}
48		source := strings.TrimSpace(parts[0])
49		target := strings.TrimSpace(parts[1])
50		if source == "" || target == "" {
51			return RefMapping{}, fmt.Errorf("invalid --map %q, expected src:dst", raw)
52		}
53		return RefMapping{Source: source, Target: target}, nil
54	}
55	
56	// ParseHaveRef normalizes a have-ref CLI value. Short names are treated as
57	// branch names for compatibility with other CLI ref selectors.
58	func ParseHaveRef(raw string) plumbing.ReferenceName {
59		raw = strings.TrimSpace(raw)
60		if strings.HasPrefix(raw, "refs/") {
61			return plumbing.ReferenceName(raw)
62		}
63		return plumbing.NewBranchReferenceName(raw)
64	}
65	
66	// NormalizeMapping validates and normalizes a single ref mapping.
67	func NormalizeMapping(m RefMapping) (NormalizedMapping, error) {
68		src := strings.TrimSpace(m.Source)
69		dst := strings.TrimSpace(m.Target)
70		if src == "" || dst == "" {
71			return NormalizedMapping{}, fmt.Errorf("invalid mapping %q:%q: source and target must be non-empty", m.Source, m.Target)
72		}
73	
74		srcFQ := strings.HasPrefix(src, "refs/")
75		dstFQ := strings.HasPrefix(dst, "refs/")
76	
77		if srcFQ && dstFQ {
78			sourceRef := plumbing.ReferenceName(src)
79			targetRef := plumbing.ReferenceName(dst)
80			srcKind := refKind(sourceRef)
81			dstKind := refKind(targetRef)
82			if srcKind == "" {
83				return NormalizedMapping{}, fmt.Errorf("unsupported source ref kind: %s", src)
84			}
85			if dstKind == "" {
86				return NormalizedMapping{}, fmt.Errorf("unsupported target ref kind: %s", dst)
87			}
88			if srcKind != dstKind {
89				return NormalizedMapping{}, fmt.Errorf("cross-kind mapping not allowed: %s (%s) -> %s (%s)", src, srcKind, dst, dstKind)
90			}
91			return NormalizedMapping{SourceRef: sourceRef, TargetRef: targetRef}, nil
92		}
93	
94		if !srcFQ && !dstFQ {
95			return NormalizedMapping{
96				SourceRef: plumbing.NewBranchReferenceName(src),
97				TargetRef: plumbing.NewBranchReferenceName(dst),
98			}, nil
99		}
100	
101		return NormalizedMapping{}, fmt.Errorf("ambiguous mapping: cannot mix fully-qualified and short ref names: %q -> %q", src, dst)
102	}
103	
104	// ValidateMappings normalizes all mappings and rejects duplicate target refs.
105	func ValidateMappings(mappings []RefMapping) ([]NormalizedMapping, error) {
106		if len(mappings) == 0 {
107			return nil, nil
108		}
109	
110		normalized := make([]NormalizedMapping, 0, len(mappings))
111		targetSeen := make(map[plumbing.ReferenceName]string, len(mappings))
112	
113		for _, m := range mappings {
114			nm, err := NormalizeMapping(m)
115			if err != nil {
116				return nil, err
117			}
118			if prev, exists := targetSeen[nm.TargetRef]; exists {
119				return nil, fmt.Errorf("duplicate target ref %s: mapped from both %q and %q", nm.TargetRef, prev, m.Source)
120			}
121			targetSeen[nm.TargetRef] = m.Source
122			normalized = append(normalized, nm)
123		}
124		return normalized, nil
125	}
126	
127	func refKind(name plumbing.ReferenceName) string {
128		switch {
129		case name.IsBranch():
130			return "branch"
131		case name.IsTag():
132			return "tag"
133		default:
134			return ""
135		}
136	}
