601	// defaultOperationMode returns the starting value for the --mode flag.
602	// Subcommands that pin a mode (sync, replicate) pass it in; plan passes ""
603	// and gets sync as the default, letting --mode override it.
604	func defaultOperationMode(defaultMode gitsync.OperationMode) operationMode {
605		if defaultMode != "" {
606			return operationMode(defaultMode)
607		}
608		return operationMode(gitsync.ModeSync)
