710		_, reason := planner.CanBootstrapRelay(cfg.Force, cfg.Prune, desiredRefs, s.target.refMap)
711		result, err := bootstrapWithInputs(ctx, s, desiredRefs, s.target.refMap, reason)
712		result.Measurement = s.measurementDone()
