90	// BuildPlans generates the action plans for each managed ref.
91	func BuildPlans(
92		store storer.EncodedObjectStorer,
93		desired map[plumbing.ReferenceName]DesiredRef,
94		targetRefs map[plumbing.ReferenceName]plumbing.Hash,
95		managed map[plumbing.ReferenceName]ManagedTarget,
96		cfg PlanConfig,
97	) ([]BranchPlan, error) {
98		if cfg.Prune {
99			for targetRef := range targetRefs {
100				if _, ok := managed[targetRef]; ok {
101					continue
102				}
103				switch {
104				case targetRef.IsTag() && cfg.IncludeTags:
105					managed[targetRef] = ManagedTarget{Kind: RefKindTag, Label: targetRef.Short()}
106				case targetRef.IsBranch() && len(cfg.Mappings) == 0 && len(cfg.Branches) == 0:
107					managed[targetRef] = ManagedTarget{Kind: RefKindBranch, Label: targetRef.Short()}
108				}
109			}
110		}
111	
112		targetNames := make([]plumbing.ReferenceName, 0, len(managed))
113		for name := range managed {
114			targetNames = append(targetNames, name)
115		}
116		sort.Slice(targetNames, func(i, j int) bool { return targetNames[i] < targetNames[j] })
117	
118		plans := make([]BranchPlan, 0, len(targetNames))
119		for _, targetRef := range targetNames {
120			info := managed[targetRef]
121			want, existsInDesired := desired[targetRef]
122			targetHash, existsOnTarget := targetRefs[targetRef]
123	
124			if !existsInDesired {
125				if cfg.Prune && existsOnTarget {
126					plans = append(plans, BranchPlan{
127						Branch:     info.Label,
128						TargetRef:  targetRef,
129						TargetHash: targetHash,
130						Kind:       info.Kind,
131						Action:     ActionDelete,
132						Reason:     ShortHash(targetHash) + " -> <deleted>",
133					})
134				}
135				continue
136			}
137	
138			if !existsOnTarget {
139				plans = append(plans, BranchPlan{
140					Branch:     want.Label,
141					SourceRef:  want.SourceRef,
142					TargetRef:  want.TargetRef,
143					SourceHash: want.SourceHash,
144					Kind:       want.Kind,
145					Action:     ActionCreate,
146					Reason:     ShortHash(want.SourceHash) + " -> <new>",
147				})
148				continue
149			}
150	
151			plan, err := PlanRef(store, want, targetHash, cfg.Force)
152			if err != nil {
153				return nil, err
154			}
155			plans = append(plans, plan)
156		}
157	
158		sort.Slice(plans, func(i, j int) bool {
159			return plans[i].TargetRef.String() < plans[j].TargetRef.String()
160		})
161		return plans, nil
162	}
