264	// PlanRef determines the action for a single ref that exists on both source and target.
265	func PlanRef(store storer.EncodedObjectStorer, want DesiredRef, targetHash plumbing.Hash, force bool) (BranchPlan, error) {
266		plan := BranchPlan{
267			Branch:     want.Label,
268			SourceRef:  want.SourceRef,
269			TargetRef:  want.TargetRef,
270			SourceHash: want.SourceHash,
271			TargetHash: targetHash,
272			Kind:       want.Kind,
273		}
274	
275		if want.SourceHash == targetHash {
276			plan.Action = ActionSkip
277			plan.Reason = ShortHash(want.SourceHash) + " already current"
278			return plan, nil
279		}
280	
281		if want.Kind == RefKindTag {
282			if force {
283				plan.Action = ActionUpdate
284				plan.Reason = ShortHash(targetHash) + " -> " + ShortHash(want.SourceHash) + " (force tag update)"
285				return plan, nil
286			}
287			plan.Action = ActionBlock
288			plan.Reason = ShortHash(targetHash) + " differs from " + ShortHash(want.SourceHash) + "; use --force to retarget tag"
289			return plan, nil
290		}
291	
292		isFF, err := ReachesCommit(store, want.SourceHash, targetHash)
293		if err != nil {
294			if errors.Is(err, ErrAncestryDepthExceeded) {
295				// Can't prove fast-forward within depth limit — block with explanation.
296				plan.Action = ActionBlock
297				plan.Reason = "ancestry check for " + want.TargetRef.String() + " exceeded depth limit; use --force if this is a valid fast-forward"
298				return plan, nil
299			}
300			return plan, fmt.Errorf("check fast-forward for %s: %w", want.TargetRef, err)
301		}
302		if isFF {
303			plan.Action = ActionUpdate
304			plan.Reason = ShortHash(targetHash) + " -> " + ShortHash(want.SourceHash)
305			return plan, nil
306		}
307	
308		if force {
309			plan.Action = ActionUpdate
310			plan.Reason = ShortHash(targetHash) + " -> " + ShortHash(want.SourceHash) + " (force)"
311			return plan, nil
312		}
313	
314		plan.Action = ActionBlock
315		plan.Reason = ShortHash(targetHash) + " is not an ancestor of " + ShortHash(want.SourceHash)
316		return plan, nil
317	}
