354	// MaxAncestryDepth is the maximum number of commits to visit during a
355	// fast-forward ancestry check. This prevents full graph walks on very
356	// large histories (issue #16). Set high enough to avoid false negatives
357	// on real repos — even the Linux kernel has ~1.3M commits.
358	const MaxAncestryDepth = 2_000_000
359	
360	// ErrAncestryDepthExceeded is returned when ReachesCommit exceeds MaxAncestryDepth.
361	var ErrAncestryDepthExceeded = errors.New("ancestry check exceeded depth limit")
362	
363	// ReachesCommit checks whether the commit at startHash has targetHash as an
364	// ancestor, bounded to MaxAncestryDepth commits to prevent degenerate walks.
365	func ReachesCommit(store storer.EncodedObjectStorer, startHash, targetHash plumbing.Hash) (bool, error) {
366		if startHash == targetHash {
367			return true, nil
368		}
369	
370		start, err := object.GetCommit(store, startHash)
371		if err != nil {
372			return false, fmt.Errorf("load source commit %s: %w", startHash, err)
373		}
374	
375		seen := map[plumbing.Hash]struct{}{}
376		stack := []*object.Commit{start}
377	
378		for len(stack) > 0 {
379			if len(seen) >= MaxAncestryDepth {
380				return false, ErrAncestryDepthExceeded
381			}
382			current := stack[len(stack)-1]
383			stack = stack[:len(stack)-1]
384			if _, ok := seen[current.Hash]; ok {
385				continue
386			}
387			seen[current.Hash] = struct{}{}
388	
389			for _, parentHash := range current.ParentHashes {
390				if parentHash == targetHash {
391					return true, nil
392				}
393				if _, ok := seen[parentHash]; ok {
394					continue
395				}
396				parent, err := object.GetCommit(store, parentHash)
397				if err != nil {
398					if errors.Is(err, plumbing.ErrObjectNotFound) {
399						continue
400					}
401					return false, fmt.Errorf("load parent commit %s: %w", parentHash, err)
402				}
403				stack = append(stack, parent)
404			}
405		}
406		return false, nil
407	}
