package syncertest

import (
	"fmt"

	"github.com/go-git/go-git/v6/x/plugin"
	xconfig "github.com/go-git/go-git/v6/x/plugin/config"
)

// init registers go-git's empty ConfigLoader so tests are insulated from
// system and global git configuration. Without this, settings the developer
// or CI image happens to carry — most commonly commit.gpgSign or
// tag.gpgSign — leak into in-memory test repos and abort wt.Commit with
// "cannot auto-sign commit". Registration replaces go-git's default Auto
// loader; the call must run before any go-git Repository operation, so it
// lives in package init rather than a test helper.
func init() {
	if err := plugin.Register(plugin.ConfigLoader(), func() plugin.ConfigSource {
		return xconfig.NewEmpty()
	}); err != nil {
		panic(fmt.Sprintf("syncertest: register empty config loader: %v", err))
	}
}

